class Solution {
public:
    int numberOfSubstrings(string s) {
        int count[3] = {0}, res = 0;
        int left = 0;
        for (int right = 0; right < s.size(); ++right) {
            count[s[right] - 'a']++;
            while (count[0] > 0 && count[1] > 0 && count[2] > 0) {
                res += s.size() - right;
                count[s[left] - 'a']--;
                left++;
            }
        }
        return res;
    }
};
```
